export default function DocumentReviewFlow() {
  const [clients, setClients] = React.useState([]);
  const [selectedClientId, setSelectedClientId] = React.useState(null);
  const [documents, setDocuments] = React.useState([]);
  const [clientInfo, setClientInfo] = React.useState(null);
  const [loadingClients, setLoadingClients] = React.useState(true);
  const [loadingDocs, setLoadingDocs] = React.useState(false);
  const [actionState, setActionState] = React.useState({});
  const [noteValues, setNoteValues] = React.useState({});
  const [search, setSearch] = React.useState("");

  React.useEffect(() => {
    tools.host_listClients({ filter: null, q: null }).then(res => {
      setClients(res.data || []);
      setLoadingClients(false);
    });
  }, []);

  const filteredClients = React.useMemo(() => {
    if (!search.trim()) return clients;
    const q = search.toLowerCase();
    return clients.filter(c => (c.name || "").toLowerCase().includes(q));
  }, [clients, search]);

  function selectClient(client) {
    setSelectedClientId(client.id);
    setClientInfo(client);
    setDocuments([]);
    setActionState({});
    setNoteValues({});
    setLoadingDocs(true);
    tools.host_listClientDocuments({ id: client.id }).then(res => {
      setDocuments(res.data || []);
      setLoadingDocs(false);
    });
  }

  async function handleVerify(doc) {
    setActionState(s => ({ ...s, [doc.id]: "pending" }));
    const res = await tools.host_setDocumentStatus({
      id: selectedClientId,
      docId: doc.id,
      body: { action: "verify", fileName: doc.fileName || doc.file_name || "", reason: "" }
    });
    if (res && res.status === "pending-approval") {
      setActionState(s => ({ ...s, [doc.id]: "awaiting-approval" }));
    } else {
      setActionState(s => ({ ...s, [doc.id]: "verified" }));
      setDocuments(prev => prev.map(d => d.id === doc.id ? { ...d, status: "verified" } : d));
    }
  }

  async function handleReject(doc) {
    const reason = noteValues[doc.id] || "";
    if (!reason.trim()) {
      setActionState(s => ({ ...s, [doc.id]: "needs-reason" }));
      return;
    }
    setActionState(s => ({ ...s, [doc.id]: "pending" }));
    const res = await tools.host_setDocumentStatus({
      id: selectedClientId,
      docId: doc.id,
      body: { action: "reject", fileName: doc.fileName || doc.file_name || "", reason }
    });
    if (res && res.status === "pending-approval") {
      setActionState(s => ({ ...s, [doc.id]: "awaiting-approval" }));
    } else {
      setActionState(s => ({ ...s, [doc.id]: "rejected" }));
      setDocuments(prev => prev.map(d => d.id === doc.id ? { ...d, status: "missing", rejectionNote: reason } : d));
    }
  }

  const reviewable = documents.filter(d => d.status === "received" || d.status === "needs_review");
  const verified = documents.filter(d => d.status === "verified");
  const missing = documents.filter(d => d.status === "missing");

  const statusTone = {
    verified: "success",
    received: "accent",
    needs_review: "warning",
    missing: "danger",
    rejected: "danger"
  };

  const statusLabel = {
    verified: "Verified",
    received: "Received",
    needs_review: "Needs review",
    missing: "Missing",
    rejected: "Rejected"
  };

  return (
    <Stack gap={4}>
      <Row gap={3} style={{ alignItems: "flex-start" }}>
        <Surface style={{ width: 280, minWidth: 220, maxWidth: 320, flexShrink: 0 }}>
          <Stack gap={2}>
            <Text variant="heading" text="Clients" />
            <Input
              label=""
              placeholder="Search clients…"
              value={search}
              onChange={e => setSearch(typeof e === "string" ? e : e?.target?.value || "")}
            />
            {loadingClients && <Text variant="caption" text="Loading clients…" />}
            {!loadingClients && filteredClients.length === 0 && (
              <Text variant="caption" text="No clients found." />
            )}
            <Stack gap={1} style={{ maxHeight: 480, overflowY: "auto" }}>
              {filteredClients.map(client => (
                <div
                  key={client.id}
                  onClick={() => selectClient(client)}
                  style={{
                    padding: "10px 12px",
                    borderRadius: "var(--vendo-radius-small)",
                    cursor: "pointer",
                    background: selectedClientId === client.id ? "var(--vendo-color-accent)" : "transparent",
                    color: selectedClientId === client.id ? "var(--vendo-color-accent-text)" : "var(--vendo-color-text)",
                    fontFamily: "var(--vendo-font-family)",
                    fontSize: "var(--vendo-font-size)",
                    borderBottom: "1px solid var(--vendo-color-border)",
                    transition: "background 0.15s"
                  }}
                >
                  <div style={{ fontWeight: 600 }}>{client.name}</div>
                  {client.entityType && (
                    <div style={{ fontSize: "0.82em", opacity: 0.7, marginTop: 2 }}>{client.entityType}</div>
                  )}
                  {client.assignedStaff && (
                    <div style={{ fontSize: "0.78em", opacity: 0.6, marginTop: 1 }}>{client.assignedStaff}</div>
                  )}
                </div>
              ))}
            </Stack>
          </Stack>
        </Surface>

        <Stack gap={3} style={{ flex: 1, minWidth: 0 }}>
          {!selectedClientId && (
            <Surface>
              <Stack gap={2} style={{ alignItems: "center", padding: "40px 0" }}>
                <Text variant="heading" text="Select a client" />
                <Text variant="caption" text="Choose a client from the list to review their uploaded documents." />
              </Stack>
            </Surface>
          )}

          {selectedClientId && (
            <Stack gap={3}>
              <Surface>
                <Row gap={3} style={{ alignItems: "center", justifyContent: "space-between", flexWrap: "wrap" }}>
                  <Stack gap={1}>
                    <Text variant="heading" text={clientInfo?.name || ""} />
                    <Row gap={2}>
                      {clientInfo?.entityType && <Badge label={clientInfo.entityType} tone="neutral" />}
                      {clientInfo?.assignedStaff && <Text variant="caption" text={clientInfo.assignedStaff} />}
                    </Row>
                  </Stack>
                  <Row gap={3}>
                    <Stack gap={0} style={{ textAlign: "center" }}>
                      <Text variant="heading" text={String(reviewable.length)} />
                      <Text variant="caption" text="To review" />
                    </Stack>
                    <Stack gap={0} style={{ textAlign: "center" }}>
                      <Text variant="heading" text={String(verified.length)} />
                      <Text variant="caption" text="Verified" />
                    </Stack>
                    <Stack gap={0} style={{ textAlign: "center" }}>
                      <Text variant="heading" text={String(missing.length)} />
                      <Text variant="caption" text="Missing" />
                    </Stack>
                  </Row>
                </Row>
              </Surface>

              {loadingDocs && (
                <Surface>
                  <Text variant="caption" text="Loading documents…" />
                </Surface>
              )}

              {!loadingDocs && documents.length === 0 && (
                <Surface>
                  <Text variant="caption" text="No documents on this client's checklist." />
                </Surface>
              )}

              {!loadingDocs && reviewable.length > 0 && (
                <Stack gap={2}>
                  <Text variant="heading" text="Ready to review" />
                  {reviewable.map(doc => {
                    const state = actionState[doc.id];
                    const isActed = state === "verified" || state === "rejected" || state === "awaiting-approval";
                    return (
                      <Surface key={doc.id}>
                        <Stack gap={2}>
                          <Row gap={2} style={{ alignItems: "center", justifyContent: "space-between", flexWrap: "wrap" }}>
                            <Stack gap={1}>
                              <Text variant="body" text={doc.name || doc.type || doc.id} />
                              {(doc.fileName || doc.file_name) && (
                                <Text variant="caption" text={doc.fileName || doc.file_name} />
                              )}
                            </Stack>
                            <EnumBadge
                              value={doc.status}
                              labels={{ received: "Received", needs_review: "Needs review" }}
                              tones={{ received: "accent", needs_review: "warning" }}
                            />
                          </Row>

                          {state === "needs-reason" && (
                            <Callout tone="warning" title="Rejection note required">
                              Please add a note explaining why this document is being rejected.
                            </Callout>
                          )}

                          {state === "awaiting-approval" && (
                            <Callout tone="info" title="Awaiting approval">
                              This action is pending approval and will take effect once approved.
                            </Callout>
                          )}

                          {state === "verified" && (
                            <Callout tone="success" title="Verified">
                              Document marked as verified.
                            </Callout>
                          )}

                          {state === "rejected" && (
                            <Callout tone="danger" title="Rejected">
                              Document returned to client with your note.
                            </Callout>
                          )}

                          {!isActed && (
                            <Stack gap={2}>
                              <Textarea
                                label="Note to client (required for rejection)"
                                placeholder="Explain what needs to be corrected or resubmitted…"
                                rows={2}
                                value={noteValues[doc.id] || ""}
                                onChange={val => {
                                  const v = typeof val === "string" ? val : val?.target?.value || "";
                                  setNoteValues(n => ({ ...n, [doc.id]: v }));
                                }}
                              />
                              <Row gap={2}>
                                <Button
                                  label={state === "pending" ? "Verifying…" : "Verify"}
                                  variant="primary"
                                  disabled={state === "pending"}
                                  onClick={() => handleVerify(doc)}
                                />
                                <Button
                                  label={state === "pending" ? "Rejecting…" : "Reject"}
                                  variant="danger"
                                  disabled={state === "pending"}
                                  onClick={() => handleReject(doc)}
                                />
                              </Row>
                            </Stack>
                          )}
                        </Stack>
                      </Surface>
                    );
                  })}
                </Stack>
              )}

              {!loadingDocs && reviewable.length === 0 && documents.length > 0 && (
                <Callout tone="success" title="Nothing to review">
                  All uploaded documents have been reviewed. Nothing is waiting for action.
                </Callout>
              )}

              {!loadingDocs && verified.length > 0 && (
                <Stack gap={2}>
                  <Text variant="heading" text="Verified" />
                  <DataTable
                    rows={verified}
                    columns={[
                      { key: "name", label: "Document" },
                      { key: "fileName", label: "File" },
                      { key: "status", label: "Status", format: "enum" }
                    ]}
                    emptyState="No verified documents."
                  />
                </Stack>
              )}

              {!loadingDocs && missing.length > 0 && (
                <Stack gap={2}>
                  <Text variant="heading" text="Missing" />
                  <DataTable
                    rows={missing}
                    columns={[
                      { key: "name", label: "Document" },
                      { key: "rejectionNote", label: "Last rejection note" },
                      { key: "status", label: "Status", format: "enum" }
                    ]}
                    emptyState="No missing documents."
                  />
                </Stack>
              )}
            </Stack>
          )}
        </Stack>
      </Row>
    </Stack>
  );
}
